+    TYPE (gsl_block) *w = FUNCTION (gsl_block, calloc) (N);
+
+    FILE *f = fopen ("test.txt", "r");
+
+    FUNCTION (gsl_block, fscanf) (f, w);
+
+    status = 0;
+    for (i = 0; i < N; i++)
+      {
+        if (w->data[2 * i] != (ATOMIC) i || w->data[2 * i + 1] != (ATOMIC) (10*i + 1))
+          status = 1;
+      };
