+    m_memory = (unsigned char*)malloc(m_size);
+    m_address = m_memory;
+  }
+
+    size_t m_size;
+    size_t m_used;
+    size_t m_capacity;
+    unsigned char* m_memory;
+    unsigned char* m_address;
+
+    template <typename T>
+      void* alloc(size_t required, long& offset)
+      {
+        required = (sizeof(T) * required);
+
+        if((m_capacity - m_used) < required)
