+
+      int numChildren = 0;
+      for(size_t i = start; i < (start + size); ++i)
+      {
+        unsigned char index = getIndex(m_points[i], bbox);
+//        octPoints[index].push_back(point);
+        octSizes[index]++;
+        if(!(oct->m_valid & (1 << index)))
+        {
+          //std::cout << "setting new valid " << index << std::endl;
+          oct->m_valid |= (1 << index);
