+  template <typename BaseVecT>
+    void PointOctree<BaseVecT>::genDisplayLists(Leaf* leaf)
+    {
+      leaf->m_listIndex = glGenLists(5);
+      for(int i = 0; i < 5; ++i)
+      {
+        glNewList(leaf->m_listIndex + i, GL_COMPILE);
+        glBegin(GL_POINTS);
+
+        size_t mod = 1;
+        if(i == 9)
+        {
+          if(8 < leaf->m_size)
+            mod = leaf->m_size / 8;
+        }
+        else if(i == 8)
+        {
+          if(16 < leaf->m_size)
+            mod = leaf->m_size / 16;
+        }
+        else if(i == 7)
+        {
+          if(32 < leaf->m_size)
+            mod = leaf->m_size / 32;
+        }
+        else if(i == 6)
+        {
+          if(64 < leaf->m_size)
+            mod = leaf->m_size / 64;
+        }
+        else if(i == 5)
+        {
+          if(128 < leaf->m_size)
+            mod = leaf->m_size / 128;
+        }
+        else if(i == 4)
+        {
+          if(256 < leaf->m_size)
+            mod = leaf->m_size / 256;
+        }
+         else if(i == 3)
+        {
+          if(512 < leaf->m_size)
+            mod = leaf->m_size / 512;
+        }
+        else if(i == 2)
+        {
+          if(1024 < leaf->m_size)
+            mod = leaf->m_size / 1024;
+        }
+        else if(i == 1)
+        {
+          if(2048 < leaf->m_size)
+            mod = leaf->m_size / 2048;
+        }
+ 
+ 
+        
+        for(size_t j = leaf->m_start;
+            j < (leaf->m_start + leaf->m_size);
+            ++j)
+        {
+          if(j % mod)
+            continue;
+
+          glColor3f(255.0f, 255.0f, 255.0f);
+          glVertex3f(m_points[j].x,
+              m_points[j].y,
+              m_points[j].z);
+        }
+        glEnd();
+        glEndList();
+      }
+    }
