+      }
+      else
+      {
+        BOct* child = getChildPtr<BOct>(oct);
+        for(unsigned char i = 0; i < 8; ++i)
+        {
+          if(oct->m_valid & (1 << i))
+          {
+            genDisplayLists(child + cnt++);
+          }
+        }
