+    const double MSRMetric<BaseVecT, BoxT>::get_distance(PointsetSurfacePtr<BaseVecT> surface, vector<coord<float>*> points,  BaseVecT corners[], DualLeaf<BaseVecT, BoxT> *leaf, bool dual)
