+bool Options::printUsage() const
+{
+    if (m_variables.count("help"))
+    {
+        cout << endl;
+        cout << m_descr << endl;
+        return true;
+    }
+    else if (!m_variables.count("inputFile"))
+    {
+        cout << "Error: You must specify an input file." << endl;
+        cout << endl;
+        cout << m_descr << endl;
+        return true;
+    }
+    return false;
+}
