+vector<float> Options::getFlippoint() const
+{
+    vector<float> dest;
+    if (m_variables.count("flipPoint"))
+    {
+        dest = (m_variables["flipPoint"].as<vector<float>>());
+        if (dest.size() != 3)
+        {
+            dest.clear();
+            dest.push_back(10000000);
+            dest.push_back(10000000);
+            dest.push_back(10000000);
+        }
+    }
+    else
+    {
+        dest.push_back(10000000);
+        dest.push_back(10000000);
+        dest.push_back(10000000);
+    }
+    return dest;
+}
