+                texture.m_data[(y_dim - y - 1) * (x_dim * 3) + x * 3 + 0] = 255 *(1-gradient);
+                texture.m_data[(y_dim - y - 1) * (x_dim * 3) + x * 3 + 1] = 255 *(1-gradient);
+                texture.m_data[(y_dim - y - 1) * (x_dim * 3) + x * 3 + 2] = 255;
+            }
+            
+            ++progress_color;
+            
+        }
+    }
