+            }
+            else if(distance[(y_dim - y - 1) * (x_dim) + x] >= 0)
+            {
+                float gradient = distance[(y_dim - y - 1) * (x_dim) + x]/max_distance;
+
+                texture.m_data[(y_dim - y - 1) * (x_dim * 3) + x * 3 + 0] = 255;
+                texture.m_data[(y_dim - y - 1) * (x_dim * 3) + x * 3 + 1] = 255 *(1-gradient);
