+        ("flipPoint", value< vector<float> >()->multitoken(), "Flippoint --flipPoint x y z" )
+        ("texFromImages,q", "Foo Bar ............")
+        ("projectDir,a", value<string>()->default_value(""), "Foo Bar ............")
+    ;
