+
+    switch ( _idx )
+    {
+        case 0 : break;
+        case 1 : _x += _size; break;
+        case 2 : _y += _size; break;
+        case 3 : _x += _size; _y += _size; break;
+        case 4 : _z += _size; break;
+        case 5 : _x += _size; _z += _size; break;
