+
+template <typename BaseVecT, typename BoxT, typename T_CellData>
+void C_Octree< BaseVecT, BoxT, T_CellData >::MovePickedCellLeft(double* _mvm)
+{
+    MovePickedCell(0, _mvm);
+}
