+class sort_indices
+{
+   private:
+     uintArr faceMaterialIndices;
+   public:
+     sort_indices(uintArr faceMaterialIndices) : faceMaterialIndices(faceMaterialIndices) {}
+     bool operator()(int i, int j) { return faceMaterialIndices[i]<faceMaterialIndices[j]; }
+};
