+ /**
+ * @file       TextureIO.cpp
+ * @brief      I/O support for texture package files (implementation).
+ * @author     Kim Oliver Rinnewitz (krinnewitz), krinnewitz@uos.de
+ * @date       Created:       2012-04-22 13:28:28
+ */
+
+
+#include <lvr/io/TextureIO.hpp>
+
